class Solution {
public:
    Node* flatten(Node* head) {
        if (!head) return head;
        Node* cur = head;
        while (cur) {
            if (cur->child) {
                Node* nxt = cur->next;
                Node* ch = flatten(cur->child);
                cur->next = ch; ch->prev = cur;
                Node* tail = ch;
                while (tail->next) tail = tail->next;
                tail->next = nxt; if (nxt) nxt->prev = tail;
                cur->child = nullptr;
            }
            cur = cur->next;
        }
        return head;
    }
};
